        private readonly string[] permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" };
        private readonly long fileSizeLimit = 10 * 1024 * 1024; // 10 MB

        [HttpPost("upload")]
